public class Wypisywanie {
    public static void main(String[] args) {
        // println - każde wywołanie to nowa linia:
        System.out.println("Linia pierwsza");
        System.out.println("Linia druga");
        System.out.println(); // pusta linia

        // print - kontynuuje w tej samej linii:
        System.out.print("Ala ");
        System.out.print("ma ");
        System.out.println("kota."); // dopiero tu nowa linia

        // printf - formatowane wypisywanie:
        int wiek = 17;
        double srednia = 4.75;
        System.out.printf("Wiek: %d lat, srednia: %.2f%n", wiek, srednia);
