}

public class PulapkaDouble {
    public static void main(String[] args) {
        double a = 0.1, b = 0.2;
        System.out.println("0.1 + 0.2 = " + (a + b)); // 0.30000000000000004 !!

        // Nigdy nie rób tak:
        if (a + b == 0.3) System.out.println("rowne"); // NIE wypisze!

        // Poprawne porównanie z epsilon:
        if (Math.abs(a + b - 0.3) < 1e-10) {
            System.out.println("Wystarczajaco rowne"); // wypisze
        }
    }
}

