public class ASCIIDemo {
    public static void main(String[] args) {
        // Wypisanie wartości liczbowych znaków:
        System.out.println((int)'A'); // 65
        System.out.println((int)'a'); // 97
        System.out.println((int)'0'); // 48

        // Zamiana znaku na liczbę:
        char c = '7';
        int cyfra = c - '0'; // 55 - 48 = 7
        System.out.println("Znak '7' jako liczba: " + cyfra);

        // Zamiana wielkiej litery na małą:
        char wielka = 'G';
        char mala = (char)(wielka + 32);
        System.out.println("'G' -> '" + mala + "'"); // g

        // Sprawdzenie rodzaju znaku bez gotowych metod:
        char x = 'k';
        boolean czyLitera = (x >= 'A' && x <= 'Z') || (x >= 'a' && x <= 'z');
        boolean czyCyfra  = (x >= '0' && x <= '9');
        System.out.println("Litera: " + czyLitera + ", Cyfra: " + czyCyfra);

        // Wypisanie całego zakresu A-Z z wartościami:
        for (char ch = 'A'; ch <= 'Z'; ch++) {
            System.out.print(ch + "=" + (int)ch + " ");
        }
    }
}

