public class SwitchDemo {
    public static void main(String[] args) {
        int dzien = 3; // 1=pon, 2=wt, ..., 7=nd

        switch (dzien) {
            case 1:
                System.out.println("Poniedzialek");
                break;
            case 2:
                System.out.println("Wtorek");
                break;
            case 3:
                System.out.println("Sroda");
                break;
            case 4:
                System.out.println("Czwartek");
                break;
            case 5:
                System.out.println("Piatek");
                break;
            case 6:
            case 7: // celowy fall-through: 6 i 7 dają ten sam wynik
                System.out.println("Weekend!");
                break;
            default:
                System.out.println("Nieprawidlowy dzien");
        }
    }
}

public class LiczbaDni {
    public static void main(String[] args) {
        int miesiac = 4;
        int rok = 2024;
        int dni;

        switch (miesiac) {
            case 1: case 3: case 5: case 7:
            case 8: case 10: case 12:
                dni = 31;
                break;
            case 4: case 6: case 9: case 11:
                dni = 30;
                break;
            case 2:
                boolean przestepny =
                    (rok % 4 == 0 && rok % 100 != 0) || rok % 400 == 0;
                dni = przestepny ? 29 : 28;
                break;
            default:
                dni = -1;
                System.out.println("Nieprawidlowy miesiac!");
        }

        if (dni > 0)
            System.out.println("Miesiac " + miesiac + "/" + rok + " ma " + dni + " dni");
    }
}

