public class ForPodstawowy {
    public static void main(String[] args) {
        // Od 1 do 10 włącznie:
        for (int i = 1; i <= 10; i++) {
            System.out.print(i + " ");
        }
        System.out.println();

        // Parzyste od 0 do 20:
        for (int i = 0; i <= 20; i += 2) {
            System.out.print(i + " ");
        }
        System.out.println();

        // Odliczanie od 10 do 1:
        for (int i = 10; i >= 1; i--) {
            System.out.print(i + " ");
        }
        System.out.println();
    }
}

public class ObliczenieWPetli {
    public static void main(String[] args) {
        // Suma liczb od 1 do 100:
        int suma = 0;
        for (int i = 1; i <= 100; i++) {
            suma += i;
        }
        System.out.println("Suma 1..100 = " + suma); // 5050

        // Silnia 10! = 1*2*3*...*10:
        long silnia = 1;
        for (int i = 2; i <= 10; i++) {
            silnia *= i;
        }
        System.out.println("10! = " + silnia); // 3628800
    }
}

public class WhileDemo {
    public static void main(String[] args) {
        // Odwrócenie liczby - nie wiemy ile ma cyfr:
        int n = 12345;
        int odwrocona = 0;
        while (n > 0) {
            odwrocona = odwrocona * 10 + n % 10;
            n /= 10;
        }
        System.out.println("Odwrocona: " + odwrocona); // 54321
    }
}

public class Euklides {
    public static void main(String[] args) {
        // Algorytm Euklidesa - NWD (Największy Wspólny Dzielnik):
        int a = 48, b = 18;
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        System.out.println("NWD(48, 18) = " + a); // 6
    }
}

