public class DoWhileMath {
    public static void main(String[] args) {
        // Suma cyfr liczby - nie wiemy ile cyfr ma liczba,
        // ale zawsze mamy co najmniej jedną:
        int liczba = 12345;
        int suma = 0;

        do {
            suma += liczba % 10; // dodaj ostatnią cyfrę
            liczba /= 10;        // usuń ostatnią cyfrę
        } while (liczba > 0);

        System.out.println("Suma cyfr: " + suma); // 15
    }
}

public class BreakDemo {
    public static void main(String[] args) {
        // Znajdź pierwszą liczbę pierwszą większą od 50:
        int wynik = -1;
        for (int n = 51; n <= 200; n++) {
            boolean pierwsza = true;
            for (int d = 2; d * d <= n; d++) {
                if (n % d == 0) { pierwsza = false; break; }
            }
            if (pierwsza) { wynik = n; break; }
        }
        System.out.println("Pierwsza l. pierwsza > 50: " + wynik); // 53
    }
}

public class ContinueDemo {
    public static void main(String[] args) {
        // Suma liczb 1..20 pomijając wielokrotności 3:
        int suma = 0;
        for (int i = 1; i <= 20; i++) {
            if (i % 3 == 0) continue;
            suma += i;
        }
        System.out.println("Suma (bez wielokrotnosci 3): " + suma);
    }
}

