public class SumaSrednia {
    public static void main(String[] args) {
        int[] tab = {4, 7, 2, 9, 1, 8, 3, 6, 5};

        long suma = 0;
        for (int i = 0; i < tab.length; i++) suma += tab[i];
        double srednia = (double) suma / tab.length;
        System.out.printf("Suma: %d, Srednia: %.2f%n", suma, srednia);
    }
}

public class MinMaks {
    public static void main(String[] args) {
        int[] tab = {4, 7, 2, 9, 1, 8, 3, 6, 5};

        int min = tab[0], max = tab[0];
        int iMin = 0, iMax = 0;
        for (int i = 1; i < tab.length; i++) {
            if (tab[i] < min) { min = tab[i]; iMin = i; }
            if (tab[i] > max) { max = tab[i]; iMax = i; }
        }
        System.out.println("Min=" + min + " (poz." + iMin + ")");
        System.out.println("Max=" + max + " (poz." + iMax + ")");
    }
}

public class Wyszukiwanie {
    public static void main(String[] args) {
        int[] tab = {4, 7, 2, 9, 1, 8, 3, 6, 5, 7, 7};

        int szukana = 8;
        int pozycja = -1;
        for (int i = 0; i < tab.length; i++) {
            if (tab[i] == szukana) { pozycja = i; break; }
        }
        System.out.println(szukana + " na pozycji: " + pozycja); // 5
    }
}

public class Zliczanie {
    public static void main(String[] args) {
        int[] tab = {4, 7, 2, 9, 1, 8, 3, 6, 5, 7, 7};

        int szukana = 7;
        int ile = 0;
        for (int i = 0; i < tab.length; i++) if (tab[i] == szukana) ile++;
        System.out.println(szukana + " pojawia sie " + ile + " razy"); // 3
    }
}

public class ForEachDemo {
    public static void main(String[] args) {
        int[] oceny = {5, 4, 3, 5, 4, 2, 5};

        // for-each - czytelniej niz klasyczna for:
        int suma = 0;
        for (int ocena : oceny) {
            suma += ocena;
        }
        System.out.printf("Suma: %d, Srednia: %.2f%n",
            suma, (double)suma / oceny.length);

        // Porownanie - oba fragmenty robia to samo:
        // Klasyczna for:
        for (int i = 0; i < oceny.length; i++) {
            System.out.print(oceny[i] + " ");
        }
        System.out.println();

        // For-each:
        for (int ocena : oceny) {
            System.out.print(ocena + " ");
        }
        System.out.println();
    }
}

import java.util.Arrays;

public class AliasowanieTablic {
    public static void main(String[] args) {
        int[] oryginal = {5, 3, 1, 4, 2};

        // BLAD - to jest alias, nie kopia!
        int[] alias = oryginal;
        alias[0] = 99;
        System.out.println(oryginal[0]); // 99 - oryginał zmieniony!

        // POPRAWNE kopiowanie:
