public class EarlyReturnDemo {
    static boolean czyPierwsza(int n) {
        if (n < 2) return false;       // warunek brzegowy
        if (n == 2) return true;       // jedyna parzysta pierwsza
        if (n % 2 == 0) return false;  // pozostale parzyste
        for (int i = 3; i * i <= n; i += 2) {
            if (n % i == 0) return false;
        }
        return true;
    }

    public static void main(String[] args) {
        System.out.println(czyPierwsza(7));   // true
        System.out.println(czyPierwsza(10));  // false
