public class SilniaRekurencyjna {
    // silnia(n) = n * silnia(n-1)
    // silnia(0) = 1  <- warunek bazowy
    static long silnia(int n) {
        if (n <= 1) return 1;         // WARUNEK BAZOWY
        return n * silnia(n - 1);     // KROK REKURENCYJNY
    }

    public static void main(String[] args) {
        // Slad wykonania silnia(4):
        // silnia(4) = 4 * silnia(3)
        //           = 4 * 3 * silnia(2)
        //           = 4 * 3 * 2 * silnia(1)
        //           = 4 * 3 * 2 * 1 = 24
        for (int i = 0; i <= 10; i++) {
            System.out.println(i + "! = " + silnia(i));
        }
    }
}

public class FibonacciPorownanie {
    // Rekurencyjnie - proste ale BARDZO wolne dla duzych n!
    static int fibRek(int n) {
        if (n <= 1) return n;
        return fibRek(n-1) + fibRek(n-2);
    }

    // Iteracyjnie - szybkie:
    static long fibIter(int n) {
        if (n <= 1) return n;
        long a = 0, b = 1;
        for (int i = 2; i <= n; i++) {
            long c = a + b;
            a = b;
            b = c;
        }
        return b;
    }

    public static void main(String[] args) {
        System.out.println("Fibonacci 10 (rek):  " + fibRek(10));  // 55
        System.out.println("Fibonacci 10 (iter): " + fibIter(10)); // 55
        System.out.println("Fibonacci 50 (iter): " + fibIter(50)); // 12586269025
        // fibRek(50) trwalby minuty!
    }
}

