public class NWDiNWW {
    // Algorytm Euklidesa:
    static int nwd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    // NWW przez NWD:
    static long nww(int a, int b) {
        return (long) a / nwd(a, b) * b; // dzielen przed mnozeniem!
    }

    public static void main(String[] args) {
        System.out.println("NWD(48, 18) = "  + nwd(48, 18));  // 6
        System.out.println("NWD(100, 75) = " + nwd(100, 75)); // 25
        System.out.println("NWW(4, 6) = "    + nww(4, 6));    // 12
        System.out.println("NWW(12, 18) = "  + nww(12, 18));  // 36
    }
}

