public class Konto {
    private String wlasciciel;
    private double saldo;
    private static int liczbaKont = 0; // wspolne dla wszystkich obiektow

    Konto(String wlasciciel, double saldoPoczatkowe) {
        if (saldoPoczatkowe < 0)
            throw new IllegalArgumentException("Saldo nie moze byc ujemne!");
        this.wlasciciel = wlasciciel;
        this.saldo      = saldoPoczatkowe;
        liczbaKont++;
    }

    // Gettery:
    public double getSaldo()          { return saldo; }
    public String getWlasciciel()     { return wlasciciel; }
    public static int getLiczbeKont() { return liczbaKont; }

    // Metody operacji - zamiast setterow:
    public void wplac(double kwota) {
        if (kwota <= 0)
            throw new IllegalArgumentException("Kwota musi byc wieksza od 0!");
        saldo += kwota;
    }

    public void wyplac(double kwota) {
        if (kwota > saldo)
            throw new IllegalArgumentException("Za malo srodkow!");
        saldo -= kwota;
    }

    @Override
    public String toString() {
        return wlasciciel + ": " + saldo + " zl";
    }
}

public class Main {
    public static void main(String[] args) {
        Konto k1 = new Konto("Anna", 1000.0);
        Konto k2 = new Konto("Bob", 500.0);

        k1.wplac(500);
        k1.wyplac(200);
        System.out.println(k1);  // Anna: 1300.0 zl
        System.out.println(k2);  // Bob: 500.0 zl

        System.out.println("Liczba kont: " + Konto.getLiczbeKont()); // 2

        // k1.saldo = 999999; // BLAD - pole private!
    }
}

public class Matematyka {
    // Pole statyczne - stala wspolna dla wszystkich:
    static final double PI = 3.14159265358979;

    // Metody statyczne - nie wymagaja obiektu:
    static double polKola(double r) {
        return PI * r * r;
    }

    static double obwodKola(double r) {
        return 2 * PI * r;
    }

    static int max(int a, int b) {
        return (a > b) ? a : b;
    }
}

public class Main {
    public static void main(String[] args) {
        // Wywolanie przez nazwe klasy - nie tworzymy obiektu:
        System.out.println(Matematyka.polKola(5));   // 78.53...
        System.out.println(Matematyka.obwodKola(5)); // 31.41...
        System.out.println(Matematyka.max(10, 20));  // 20
        System.out.println(Matematyka.PI);           // 3.14159...
    }
}

