public abstract class Ksztalt {
    protected String nazwa;
    protected String kolor;

    Ksztalt(String nazwa, String kolor) {
        this.nazwa = nazwa;
        this.kolor = kolor;
    }

    // Metody abstrakcyjne - klasy potomne MUSZĄ je zaimplementowac:
    abstract double pole();
    abstract double obwod();

    // Metoda konkretna - wspolna dla wszystkich:
    void wypisz() {
        System.out.printf("%s (%s): pole=%.2f, obwod=%.2f%n",
            nazwa, kolor, pole(), obwod());
    }
}

public class Kwadrat extends Ksztalt {
    private double bok;

    Kwadrat(double bok) {
        super("Kwadrat", "zielony");
        this.bok = bok;
    }

    @Override
    double pole()  { return bok * bok; }

    @Override
    double obwod() { return 4 * bok; }
}

public class Trojkat extends Ksztalt {
    private double a, b, c;

    Trojkat(double a, double b, double c) {
        super("Trojkat", "pomaranczowy");
        this.a = a;
        this.b = b;
        this.c = c;
    }

    @Override
    double pole() {
        // Wzor Herona:
        double s = (a + b + c) / 2;
        return Math.sqrt(s * (s-a) * (s-b) * (s-c));
    }

    @Override
    double obwod() { return a + b + c; }
}

public class Main {
    public static void main(String[] args) {
        // Ksztalt k = new Ksztalt("?", "?"); // BLAD - klasa abstrakcyjna!

        Ksztalt[] ksztalty = {
            new Kwadrat(5),
            new Trojkat(3, 4, 5)
        };
        for (Ksztalt ks : ksztalty) {
            ks.wypisz();
        }
        // Kwadrat (zielony): pole=25.00, obwod=20.00
        // Trojkat (pomaranczowy): pole=6.00, obwod=12.00
    }
}

public interface Drukowalny {
    void drukuj();
}

public interface Porownywalny {
    int porownaj(Object inny); // zwraca ujemny, 0 lub dodatni
    default boolean wiekszy(Object inny) {
        return porownaj(inny) > 0;
    }
}

// Klasa implementuje OBA interfejsy:
public class Produkt implements Drukowalny, Porownywalny {
    private String nazwa;
    private double cena;

    Produkt(String nazwa, double cena) {
        this.nazwa = nazwa;
        this.cena  = cena;
    }

    @Override
    public void drukuj() {
        System.out.println(nazwa + ": " + cena + " zl");
    }

    @Override
    public int porownaj(Object inny) {
        Produkt p = (Produkt) inny;
        return Double.compare(this.cena, p.cena);
    }
}

public class Main {
    public static void main(String[] args) {
