        Produkt p2 = new Produkt("Herbata", 8.49);

        p1.drukuj(); // Kawa: 15.99 zl
        p2.drukuj(); // Herbata: 8.49 zl

        System.out.println(p1.wiekszy(p2)); // true - kawa drozej
