public class TryCatchDemo {
    public static void main(String[] args) {
        String[] wejscia = {"42", "abc", null, "0"};

        for (String w : wejscia) {
            try {
                int n = Integer.parseInt(w);     // moze rzucic NumberFormatException
                int wynik = 100 / n;              // moze rzucic ArithmeticException
                System.out.println("100 / " + n + " = " + wynik);
            } catch (NumberFormatException e) {
                System.out.println("Bledna liczba: '" + w + "'");
            } catch (ArithmeticException e) {
                System.out.println("Dzielenie przez zero!");
            } catch (NullPointerException e) {
                System.out.println("Wartosc null!");
            } finally {
                System.out.println("  (ten blok zawsze sie wykonuje)");
            }
        }
    }
}

public class ThrowDemo {
    static int czytajWiek(String s) {
        // Integer.parseInt moze rzucic NumberFormatException (unchecked)
        // - nie musimy jej deklarowac w throws:
        int wiek = Integer.parseInt(s);
        if (wiek < 0 || wiek > 120) {
            // throw - reczne rzucenie wyjatku:
            throw new IllegalArgumentException("Nieprawidlowy wiek: " + wiek);
        }
        return wiek;
    }

    public static void main(String[] args) {
        String[] testowe = {"17", "-5", "abc", "200"};

        for (String s : testowe) {
            try {
                int wiek = czytajWiek(s);
                System.out.println("Poprawny wiek: " + wiek);
            } catch (NumberFormatException e) {
                System.out.println("Nie liczba: " + s);
            } catch (IllegalArgumentException e) {
                System.out.println("Blad: " + e.getMessage());
            }
        }
    }
}

import java.io.*;

public class TryWithResourcesDemo {
    // Stary sposob - reczne zamykanie w finally:
    static void staryStyl(String path) {
        BufferedReader br = null;
        try {
            br = new BufferedReader(new FileReader(path));
            String linia;
            while ((linia = br.readLine()) != null)
                System.out.println(linia);
        } catch (IOException e) {
            e.printStackTrace();
        } finally {
            if (br != null) {
                try { br.close(); } catch (IOException e) {}
            }
        }
    }

    // Nowy sposob - try-with-resources (zalecany):
    static void nowyStyl(String path) {
        try (BufferedReader br = new BufferedReader(new FileReader(path))) {
            String linia;
            while ((linia = br.readLine()) != null)
                System.out.println(linia);
        } catch (FileNotFoundException e) {
            System.err.println("Brak pliku: " + e.getMessage());
        } catch (IOException e) {
            System.err.println("Blad odczytu: " + e.getMessage());
        }
        // br zamkniety automatycznie - nawet gdy wystapit wyjatek!
    }
}

// Wlasny checked exception:
public class NiedostateczneSaldoException extends Exception {
    private double brakujacaKwota;

    NiedostateczneSaldoException(double brakujacaKwota) {
        super("Za malo srodkow. Brakuje: " + brakujacaKwota + " zl");
        this.brakujacaKwota = brakujacaKwota;
    }

    double getBrakujacaKwota() { return brakujacaKwota; }
}

public class KontoBankowe {
    private double saldo;

    KontoBankowe(double saldo) { this.saldo = saldo; }

    void wyplac(double kwota) throws NiedostateczneSaldoException {
        if (kwota > saldo) {
            throw new NiedostateczneSaldoException(kwota - saldo);
        }
        saldo -= kwota;
        System.out.println("Wyplacono: " + kwota + " zl");
    }
}

public class Main {
    public static void main(String[] args) {
        KontoBankowe konto = new KontoBankowe(100.0);

        try {
            konto.wyplac(50);   // OK
            konto.wyplac(200);  // rzuci wyjatek
        } catch (NiedostateczneSaldoException e) {
            System.out.println("Blad: " + e.getMessage());
            System.out.println("Brakuje: " + e.getBrakujacaKwota() + " zl");
        }
    }
}

