import java.util.*;

public class LinkedListDemo {
    public static void main(String[] args) {
        LinkedList<Integer> kolejka = new LinkedList<>();

        // Dodawanie na koniec i poczatek:
        kolejka.addLast(1);
        kolejka.addLast(2);
        kolejka.addLast(3);
        kolejka.addFirst(0);
        System.out.println(kolejka); // [0, 1, 2, 3]

        // Pobieranie i usuwanie z poczatku (jak kolejka FIFO):
        System.out.println(kolejka.pollFirst()); // 0
        System.out.println(kolejka.pollFirst()); // 1
        System.out.println(kolejka);             // [2, 3]

        // Uzycie jako stos (LIFO):
        LinkedList<String> stos = new LinkedList<>();
        stos.push("pierwsza");
        stos.push("druga");
        stos.push("trzecia");
        System.out.println(stos.pop()); // trzecia
        System.out.println(stos.pop()); // druga
    }
}

