        HashSet<Integer> czescWspolna = new HashSet<>(A);
        czescWspolna.retainAll(B);
        System.out.println("A ∩ B: " + czescWspolna); // [3, 4, 5]

        HashSet<Integer> suma = new HashSet<>(A);
        suma.addAll(B);
        System.out.println("A ∪ B: " + suma); // [1, 2, 3, 4, 5, 6, 7]
    }
}

