import java.io.*;

public class SplitParsing {
    public static void main(String[] args) {
        // Plik ma linie postaci: "Jan Kowalski 85"
        try (BufferedReader br = new BufferedReader(
                new FileReader("uczniowie.txt"))) {
            String linia;
            int maxWynik = 0;
            String najlepszy = "";

            while ((linia = br.readLine()) != null) {
                String[] pola = linia.trim().split("\\s+");
                if (pola.length < 3) continue;
                int wynik = Integer.parseInt(pola[2]);
                if (wynik > maxWynik) {
                    maxWynik = wynik;
                    najlepszy = pola[0] + " " + pola[1];
                }
            }
            System.out.println("Najlepszy: " + najlepszy + " (" + maxWynik + ")");
        } catch (IOException e) { e.printStackTrace(); }
    }
}

import java.io.*;

public class StreamTokenizerDemo {
    public static void main(String[] args) {
        // StreamTokenizer - elegancki parser liczb z java.io:
        try (StreamTokenizer st = new StreamTokenizer(
                new BufferedReader(new FileReader("liczby.txt")))) {
            int suma = 0, ile = 0;
            while (st.nextToken() != StreamTokenizer.TT_EOF) {
                if (st.ttype == StreamTokenizer.TT_NUMBER) {
                    suma += (int) st.nval;
                    ile++;
                }
            }
            System.out.println("Wczytano " + ile + " liczb, suma=" + suma);
        } catch (IOException e) { e.printStackTrace(); }
    }
}

