import java.io.*;
import java.util.*;

public class WzorzecMaturalny {
    public static void main(String[] args) {
        List<Integer> dane = new ArrayList<>();

        // 1. Wczytaj dane z pliku:
        try (BufferedReader br = new BufferedReader(
                new FileReader("dane.txt"))) {
            String l;
            while ((l = br.readLine()) != null) {
                l = l.trim();
                if (!l.isEmpty()) dane.add(Integer.parseInt(l));
            }
        } catch (IOException e) {
            System.err.println("Blad pliku wejsciowego: " + e.getMessage());
            return;
        }

        // 2. Sprawdz czy sa dane:
        if (dane.isEmpty()) {
            System.err.println("Brak danych!");
            return;
        }

        // 3. Przetwarzanie:
        long suma = 0;
        int max = dane.get(0), min = dane.get(0);
        for (int x : dane) {
            suma += x;
            if (x > max) max = x;
            if (x < min) min = x;
        }

        // 4. Zapisz wyniki:
        try (PrintWriter pw = new PrintWriter(
                new BufferedWriter(new FileWriter("wyniki.txt")))) {
            pw.println(dane.size());
            pw.printf("%.2f%n", (double) suma / dane.size());
            pw.println(max);
            pw.println(min);
        } catch (IOException e) {
            System.err.println("Blad zapisu: " + e.getMessage());
        }

        System.out.println("Gotowe! Wyniki w wyniki.txt");
    }
}
